function (x, norm = "abm", digits = 4) 
{
    require(igraph)
    n &lt;- vcount(x)
    if (is.null(V(x)$name)) {
        V(x)$name &lt;- 1:n
        names &lt;- V(x)$name
    }
    else {
        names &lt;- V(x)$name
        V(x)$name &lt;- 1:n
    }
    norm.max &lt;- function(v) {
        v^2/max(v^2)
    }
    norm.one &lt;- function(v) {
        v^2
    }
    norm.abm &lt;- function(v) {
        abs(v)/max(abs(v))
    }
    norm.abs &lt;- function(v) {
        abs(v)
    }
    get_status &lt;- function(g) {
        nv &lt;- vcount(g)
        s_vec &lt;- numeric(nv)
        xc &lt;- components(g)
        for (k in 1:xc$no) {
            nodes_in_comp &lt;- which(xc$membership == k)
            if (length(nodes_in_comp) &gt; 1) {
                subg &lt;- induced_subgraph(g, nodes_in_comp)
                eig_sub &lt;- eigen(as_adjacency_matrix(subg, sparse = FALSE))
                s_vec[nodes_in_comp] &lt;- abs(eig_sub$vectors[, 
                  1])
            }
            else {
                s_vec[nodes_in_comp] &lt;- 0
            }
        }
        return(s_vec)
    }
    s &lt;- get_status(x)
    if (norm == "max") {
        s &lt;- norm.max(s)
    }
    if (norm == "one") {
        s &lt;- norm.one(s)
    }
    if (norm == "abm") {
        s &lt;- norm.abm(s)
    }
    if (norm == "abs") {
        s &lt;- norm.abs(s)
    }
    d &lt;- numeric(n)
    u &lt;- numeric(n)
    for (i in 1:n) {
        j &lt;- neighbors(x, i)
        xd &lt;- delete_vertices(x, i)
        ed &lt;- ecount(xd) == 0
        nd &lt;- vcount(xd)
        if (ed == 0 & nd &gt; 1) {
            sd &lt;- get_status(xd)
            if (norm == "max") {
                sd &lt;- norm.max(sd)
            }
            if (norm == "one") {
                sd &lt;- norm.one(sd)
            }
            if (norm == "abm") {
                sd &lt;- norm.abm(sd)
            }
            if (norm == "abs") {
                sd &lt;- norm.abs(sd)
            }
        }
        else {
            sd &lt;- rep(0, nd)
        }
        names(sd) &lt;- V(xd)$name
        u[i] &lt;- mean(sd[as.character(j)])
        d[i] &lt;- s[i] - u[i]
    }
    d[is.na(d)] &lt;- 0
    u[is.na(u)] &lt;- 0
    scalar &lt;- mean(u)/mean(s)
    scd &lt;- (s * scalar) - u
    dat &lt;- data.frame(d = d, scd = scd, s = s, u = u, scalar = scalar)
    dat &lt;- round(dat, digits)
    dat &lt;- data.frame(n = names, dat)
    rownames(dat) &lt;- 1:nrow(dat)
    return(dat)
}

